import{a as e,c as t,d as n,f as r,u as i,w as a,x as o,y as s}from"./runtime-core.esm-bundler-CD3o_SA6.js";import{t as c}from"./_plugin-vue_export-helper-B80Cc4Ui.js";var l={},u={class:`chapter-header`},d={class:`breadcrumb`},f={class:`page-container`},p={class:`chapter-nav`};function m(c,l){let m=o(`router-link`);return s(),t(`div`,null,[e(`header`,u,[e(`div`,d,[r(m,{to:`/`},{default:a(()=>[...l[0]||=[n(`Study Guide`,-1)]]),_:1}),l[3]||=n(` › `,-1),r(m,{to:`/sa`},{default:a(()=>[...l[1]||=[n(`SA`,-1)]]),_:1}),l[4]||=n(` › `,-1),r(m,{to:`/sa/microservices`},{default:a(()=>[...l[2]||=[n(`Microservices`,-1)]]),_:1}),l[5]||=n(` › Chapter 6 `,-1)]),l[6]||=i(`<h1>Chapter 6: Developing Business Logic with Event Sourcing</h1><p class="chapter-desc">An event-centric approach to writing business logic and persisting aggregates — where every state change becomes a first-class, permanent domain event.</p><div class="stats-bar"><span class="stat-badge">1 Core Pattern</span><span class="stat-badge">4 Problems Solved</span><span class="stat-badge">5 Benefits</span><span class="stat-badge">4 Drawbacks</span><span class="stat-badge">3 Saga Integration Approaches</span></div>`,3)]),e(`div`,f,[l[9]||=i(`<div class="toc"><h2>Table of Contents</h2><ol><li class="toc-section"><a href="#s6-1">6.1 Developing Business Logic Using Event Sourcing</a><ol><li><a href="#s6-1-1">6.1.1 The trouble with traditional persistence</a></li><li><a href="#s6-1-2">6.1.2 Overview of event sourcing</a></li><li><a href="#s6-1-3">6.1.3 Handling concurrent updates with optimistic locking</a></li><li><a href="#s6-1-4">6.1.4 Event sourcing and publishing events</a></li><li><a href="#s6-1-5">6.1.5 Using snapshots to improve performance</a></li><li><a href="#s6-1-6">6.1.6 Idempotent message processing</a></li><li><a href="#s6-1-7">6.1.7 Evolving domain events</a></li><li><a href="#s6-1-8">6.1.8 Benefits of event sourcing</a></li><li><a href="#s6-1-9">6.1.9 Drawbacks of event sourcing</a></li></ol></li><li class="toc-section"><a href="#s6-2">6.2 Implementing an Event Store</a><ol><li><a href="#s6-2-1">6.2.1 How Eventuate Local works</a></li><li><a href="#s6-2-2">6.2.2 The Eventuate client framework</a></li></ol></li><li class="toc-section"><a href="#s6-3">6.3 Using Sagas and Event Sourcing Together</a><ol><li><a href="#s6-3-1">6.3.1 Choreography-based sagas</a></li><li><a href="#s6-3-2">6.3.2 Orchestration-based sagas</a></li><li><a href="#s6-3-3">6.3.3 Implementing saga orchestrators with event sourcing</a></li></ol></li><li class="toc-section"><a href="#takeaways">Key Takeaways</a></li></ol></div><h2 class="section-title" id="s6-1">6.1 Developing Business Logic Using Event Sourcing</h2><div class="content-section"><p>Event sourcing is a different way of structuring business logic and persisting aggregates. Instead of mapping objects to rows in a database table, it persists each aggregate as a <strong>sequence of domain events</strong>. Each event represents a state change. The application recreates the current state by replaying all events from the beginning (or from a snapshot).</p><div class="pattern-summary"><h4>Pattern: Event Sourcing</h4><div class="ps-row"><span class="ps-label">What:</span> <span>Persist an aggregate as a sequence of domain events that represent state changes.</span></div><div class="ps-row"><span class="ps-label">Why:</span> <span>Eliminates the problem of event publishing being &quot;bolted on&quot; to business logic. Every aggregate creation or update <em>guarantees</em> a published event.</span></div><div class="ps-row"><span class="ps-label">Tradeoff:</span> <span>Querying the event store is often difficult — requires using CQRS (Chapter 7).</span></div></div><h3 class="subsection-title" id="s6-1-1">6.1.1 The trouble with traditional persistence</h3><p>The traditional approach maps classes to tables, fields to columns, and objects to rows. While widely used, it has four fundamental limitations when building event-driven microservices:</p><table class="comparison-table"><thead><tr><th>Problem</th><th>Description</th></tr></thead><tbody><tr><td><strong>Object-Relational impedance mismatch</strong></td><td>A fundamental conceptual mismatch between the tabular relational schema and the graph structure of a rich domain model. ORM frameworks help but don&#39;t fully solve this.</td></tr><tr><td><strong>Lack of aggregate history</strong></td><td>Traditional persistence only stores the <em>current</em> state. Once updated, the previous state is lost. Implementing history requires additional, duplicated code that must stay in sync with business logic.</td></tr><tr><td><strong>Audit logging is tedious and error prone</strong></td><td>Audit code and business logic can diverge, resulting in bugs. Applications like Jira or Asana need a history of all changes — manually implementing this is fragile.</td></tr><tr><td><strong>Event publishing is bolted on</strong></td><td>Developers must remember to manually add event-generation logic. Business logic continues to work even when the developer forgets to publish an event — a silent source of bugs.</td></tr></tbody></table><h3 class="subsection-title" id="s6-1-2">6.1.2 Overview of event sourcing</h3><p>Event sourcing builds on domain events. Each aggregate is stored in an <strong>event store</strong> as a sequence of events. Rather than rows in an <code>ORDER</code> table, the Order aggregate is a series of rows in an <code>EVENTS</code> table: <em>OrderCreated</em>, <em>OrderApproved</em>, <em>OrderShipped</em>, etc.</p><div class="info-box note-box"><p><strong>Loading an aggregate (3 steps):</strong></p><ol style="margin:0.4rem 0;padding-left:1.3rem;"><li>Load the events for the aggregate from the event store.</li><li>Create an aggregate instance using its default constructor.</li><li>Iterate through the events, calling <code>apply()</code> on each one.</li></ol><p style="margin-top:0.5rem;">This is functionally equivalent to a <em>fold/reduce</em> operation in functional programming.</p></div><p><strong>Events are non-optional.</strong> Every state change of an aggregate must emit a domain event. An event must contain all the data needed to perform the state transition. For example, an <em>OrderCreated</em> event must contain all line items, payment info, and delivery info — not just the orderId.</p><h4 class="subsubsection-title">Aggregate methods: process() and apply()</h4><p>Event sourcing refactors a traditional command method into two types of methods:</p><table class="comparison-table"><thead><tr><th>Method</th><th>Input</th><th>Output</th><th>Side effects</th></tr></thead><tbody><tr><td><code>process(Command)</code></td><td>A command object representing the request</td><td>A list of events representing state changes</td><td><strong>None</strong> — validates and returns events without modifying state. Throws exception if invalid.</td></tr><tr><td><code>apply(Event)</code></td><td>A domain event</td><td>void</td><td><strong>Updates state</strong> — cannot fail, because an event represents something that already happened.</td></tr></tbody></table><div class="info-box analogy-box"><p><strong>Analogy:</strong> Think of a bank account. Traditional persistence stores only the current balance. Event sourcing stores every transaction (deposit, withdrawal, fee) as an immutable log. You can reconstruct the balance at <em>any point in time</em> by replaying the log. This is exactly how bank ledgers have worked for centuries.</p></div><p>Creating an aggregate involves: instantiate → <code>process()</code> → <code>apply()</code> all generated events → save events.<br> Updating an aggregate involves: load events → instantiate → <code>apply()</code> loaded events → <code>process()</code> → <code>apply()</code> new events → save new events.</p><h3 class="subsection-title" id="s6-1-3">6.1.3 Handling concurrent updates with optimistic locking</h3><p>When two requests simultaneously try to update the same aggregate, event sourcing uses <strong>optimistic locking</strong> — similar to traditional persistence&#39;s VERSION column. An event store verifies that the aggregate&#39;s version (often the count of events) is unchanged before allowing a new insert. If it has changed, the second transaction fails and must retry.</p><h3 class="subsection-title" id="s6-1-4">6.1.4 Event sourcing and publishing events</h3><p>Saving an event in the event store is an atomic operation. Two publishing mechanisms from Chapter 3 work here:</p><table class="comparison-table"><thead><tr><th>Mechanism</th><th>How it works</th><th>Challenge</th></tr></thead><tbody><tr><td><strong>Polling</strong></td><td>Event publisher polls the EVENTS table for new rows (using a PUBLISHED column). Marks events as published after delivery.</td><td>Naive polling by event_id can <em>skip events</em> if transactions commit out of order. The PUBLISHED column approach prevents this.</td></tr><tr><td><strong>Transaction Log Tailing</strong></td><td>Reads the database&#39;s transaction log (binlog relay) to reliably capture all new events.</td><td>Database-specific implementation. More complex but zero risk of skipping events.</td></tr></tbody></table><h3 class="subsection-title" id="s6-1-5">6.1.5 Using snapshots to improve performance</h3><p>Replaying all events from the beginning gets slow for long-lived aggregates with thousands of events. The solution is to periodically take a <strong>snapshot</strong> of the aggregate&#39;s state. Instead of replaying from event 1, you restore the snapshot and only replay events since the last snapshot was taken.</p><p>Snapshots are especially useful for long-lived aggregates like a <em>Customer</em> account that may have made thousands of orders over years.</p><h3 class="subsection-title" id="s6-1-6">6.1.6 Idempotent message processing</h3><p>A message broker may deliver a message more than once. To handle duplicate messages idempotently:</p><ul><li><strong>RDBMS event store:</strong> Use a <code>PROCESSED_MESSAGES</code> table. Before processing, record the message ID in this table within the same transaction. Duplicate messages are detected and ignored.</li><li><strong>NoSQL event store:</strong> Store the message ID in the event itself. Check for a duplicate message ID when loading events.</li><li><strong>Pseudo events:</strong> Insert a &quot;message already processed&quot; event as a no-op to mark idempotent handling in NoSQL stores.</li></ul><h3 class="subsection-title" id="s6-1-7">6.1.7 Evolving domain events</h3><p>Over time, events need to change. A challenge: the event store contains events from every schema version. When loading an old aggregate, the application must handle legacy event structures.</p><div class="pattern-summary"><h4>Upcasting</h4><div class="ps-row"><span class="ps-label">What:</span> <span>Transform an older event format to the current schema when loading it from the event store.</span></div><div class="ps-row"><span class="ps-label">How:</span> <span>An upcaster function migrates a v1 event to a v2 event on the fly during deserialization. The event store itself never needs to be migrated.</span></div><div class="ps-row"><span class="ps-label">Benefit:</span> <span>Backward compatibility without expensive data migrations.</span></div></div><h3 class="subsection-title" id="s6-1-8">6.1.8 Benefits of event sourcing</h3><ul><li><strong>Reliable domain event publishing:</strong> Every aggregate creation or update automatically emits an event — it&#39;s impossible to forget.</li><li><strong>Complete aggregate history preserved:</strong> The event log is the source of truth. Full history is available for auditing, debugging, and regulatory compliance.</li><li><strong>Enables temporal queries:</strong> You can reconstruct the state of an aggregate at any point in time by replaying events up to that timestamp.</li><li><strong>No Object-Relational impedance mismatch:</strong> Aggregates are stored as events, not mapped to tables. Complex object graphs are serialized as JSON events.</li><li><strong>Business value:</strong> The event log itself often has direct business value — it provides an exact audit trail of all decisions made.</li></ul><h3 class="subsection-title" id="s6-1-9">6.1.9 Drawbacks of event sourcing</h3><ul><li><strong>Learning curve:</strong> It&#39;s a fundamentally different programming model that takes time to learn and adopt.</li><li><strong>Querying is harder:</strong> You can&#39;t do a simple <code>SELECT * WHERE state = &#39;APPROVED&#39;</code>. The event store only indexes by aggregate ID. You must use the CQRS pattern (Chapter 7) to build queryable views.</li><li><strong>Evolving events is complex:</strong> Changing event schemas requires upcasting and careful versioning strategy.</li><li><strong>Deleting data / GDPR:</strong> The immutable event log makes data deletion legally complex. A solution is to encrypt personal data with a per-customer key — when you delete the key, the data becomes unreadable (<em>crypto-shredding</em> / pseudonymization).</li></ul><div class="info-box warning-box"><p><strong>GDPR Challenge:</strong> The &quot;right to be forgotten&quot; is fundamentally in tension with an immutable event log. Crypto-shredding (encrypting personal data and deleting the key) provides a practical workaround, but adds architectural complexity.</p></div></div><h2 class="section-title" id="s6-2">6.2 Implementing an Event Store</h2><div class="content-section"><p>An event store is a specialized database for storing and retrieving aggregates as event sequences. Options include purpose-built stores like <strong>Event Store</strong>, <strong>Lagom</strong>, and <strong>Axon</strong>, as well as frameworks that use general-purpose databases like <strong>Eventuate Local</strong> (uses MySQL + Kafka).</p><h3 class="subsection-title" id="s6-2-1">6.2.1 How Eventuate Local works</h3><p>Eventuate Local uses a MySQL database with three tables:</p><table class="comparison-table"><thead><tr><th>Table</th><th>Purpose</th></tr></thead><tbody><tr><td><code>events</code></td><td>Stores the events. Columns: <code>event_id</code>, <code>event_type</code>, <code>entity_type</code>, <code>entity_id</code>, <code>event_data</code> (JSON).</td></tr><tr><td><code>entities</code></td><td>One row per aggregate instance. Stores the current version (number of events) to support optimistic locking.</td></tr><tr><td><code>snapshots</code></td><td>Stores snapshots of aggregate state to avoid replaying all events from the beginning.</td></tr></tbody></table><p>To subscribe to events, Eventuate Local uses a <strong>binlog relay</strong> — it reads MySQL&#39;s binary transaction log and publishes new events to Apache Kafka topics. Consumers subscribe to those topics.</p><h3 class="subsection-title" id="s6-2-2">6.2.2 The Eventuate client framework for Java</h3><p>The Eventuate framework provides base classes for writing event sourcing-based aggregates. Key abstractions:</p><ul><li><code>ReflectiveMutableCommandProcessingAggregate</code> — base class for aggregates. Uses reflection to dispatch commands to <code>process()</code> methods and events to <code>apply()</code> methods.</li><li><code>AggregateRepository</code> — provides <code>save()</code> and <code>update()</code> operations that handle the full load-process-apply-persist cycle.</li><li><code>@EventSubscriber</code> — annotation for handlers that subscribe to domain events from a specific aggregate type.</li></ul></div><h2 class="section-title" id="s6-3">6.3 Using Sagas and Event Sourcing Together</h2><div class="content-section"><p>Event sourcing and sagas complement each other well, but combining them introduces a transactional challenge: some databases (especially NoSQL) don&#39;t support multi-table transactions. Updating an aggregate and creating/updating a saga must be done atomically.</p><h3 class="subsection-title" id="s6-3-1">6.3.1 Implementing choreography-based sagas using event sourcing</h3><p>This combination is straightforward. When an aggregate is updated, events are automatically published to the message broker. Other aggregates react to those events, creating a choreography-based saga flow. The event store + broker together ensure reliable, atomic event delivery.</p><h3 class="subsection-title" id="s6-3-2">6.3.2 Creating an orchestration-based saga</h3><p>More complex. Two scenarios:</p><ul><li><strong>RDBMS event store:</strong> Use a <code>@Transactional</code> boundary to atomically update the aggregate and insert the saga command. Easy because RDBMS supports multi-table transactions.</li><li><strong>NoSQL event store:</strong> Use an event handler pattern. The aggregate emits a <em>SagaOrchestratorRequested</em> event. A separate handler reacts to this event and creates the saga orchestrator. The event store guarantees the event is published, and the handler creates the saga.</li></ul><p>Strategies for correlating saga IDs with aggregate IDs: use the aggregate ID as the saga ID, or embed the saga ID in the event data.</p><h3 class="subsection-title" id="s6-3-3">6.3.3 Implementing saga orchestrators using event sourcing</h3><p>Saga orchestrators can themselves be implemented as event-sourced aggregates. A <em>SagaOrchestratorCreated</em> event starts the saga. Each step emits a <em>SagaCommandEvent</em> that is published to the command channel. Replies come back as events (<em>SagaReplyRequested</em>). Duplicate replies are handled using the idempotency mechanisms described in section 6.1.6.</p><div class="pattern-summary"><h4>Event Sourcing + Saga Integration Summary</h4><div class="ps-row"><span class="ps-label">Choreography:</span> <span>Natural fit — events drive the saga. Publish events → other aggregates react.</span></div><div class="ps-row"><span class="ps-label">Orchestration (RDBMS):</span> <span>Use @Transactional to atomically update aggregate + create saga.</span></div><div class="ps-row"><span class="ps-label">Orchestration (NoSQL):</span> <span>Use an event handler to create the saga after an event is published.</span></div><div class="ps-row"><span class="ps-label">Saga as event-sourced aggregate:</span> <span>Store saga state as events. SagaCommandEvent per step. Idempotent reply handling.</span></div></div></div><div class="takeaways" id="takeaways"><h3>Key Takeaways — Chapter 6</h3><ul><li><strong>Event sourcing</strong> persists aggregates as a sequence of domain events rather than as table rows. The current state is reconstructed by replaying events.</li><li>Traditional persistence has four problems event sourcing solves: object-relational impedance, no history, tedious audit logging, and unreliable event publishing.</li><li>Every state change <strong>must</strong> emit a domain event. Command methods split into <code>process()</code> (validates, returns events) and <code>apply()</code> (updates state, cannot fail).</li><li><strong>Optimistic locking</strong> prevents concurrent update conflicts using the event count as a version.</li><li><strong>Snapshots</strong> are periodic captures of aggregate state to avoid replaying thousands of events on every load.</li><li><strong>Upcasting</strong> handles evolving event schemas by transforming old events to the current schema on the fly.</li><li>Benefits: reliable event publishing, full history, temporal queries, no ORM impedance, audit trail.</li><li>Drawbacks: learning curve, querying requires CQRS, schema evolution complexity, GDPR/deletion challenges (crypto-shredding workaround).</li><li><strong>Eventuate Local</strong> implements an event store on MySQL + Kafka, using three tables: <code>events</code>, <code>entities</code>, <code>snapshots</code>.</li><li>Event sourcing is a good foundation for both choreography and orchestration-based sagas, especially when combined with the CQRS pattern.</li></ul></div>`,8),e(`div`,p,[r(m,{to:`/sa/microservices/ch5`,class:`prev`},{default:a(()=>[...l[7]||=[n(`← Chapter 5`,-1)]]),_:1}),r(m,{to:`/sa/microservices/ch7`,class:`next`},{default:a(()=>[...l[8]||=[n(`Chapter 7 →`,-1)]]),_:1})])])])}var h=c(l,[[`render`,m]]);export{h as default};